import { useEffect, useState, useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

import { apiClient } from "@/App";
import { toast } from "sonner";
import { Plus, Calendar } from "lucide-react";

/* =========================
   SAFE ARRAY HELPER
========================= */
const asArray = (data) => {
  if (Array.isArray(data)) return data;
  if (Array.isArray(data?.data)) return data.data;
  if (Array.isArray(data?.students)) return data.students;
  if (Array.isArray(data?.attendance)) return data.attendance;
  return [];
};

const AttendancePage = () => {
  const [students, setStudents] = useState([]);
  const [attendance, setAttendance] = useState([]);

  const [selectedDate, setSelectedDate] = useState(
    new Date().toISOString().split("T")[0]
  );

  const [dialogOpen, setDialogOpen] = useState(false);

  const [formData, setFormData] = useState({
    entity_type: "student",
    entity_id: "",
    date: new Date().toISOString().split("T")[0],
    status: "present",
    remarks: "",
  });

  /* =========================
     FETCH DATA
  ========================= */
  useEffect(() => {
    fetchStudents();
    fetchAttendance();
  }, [selectedDate]);

  const fetchStudents = async () => {
    try {
      const res = await apiClient.get("/students");
      setStudents(asArray(res));
    } catch (error) {
      setStudents([]);
      toast.error("Failed to fetch students");
    }
  };

  const fetchAttendance = async () => {
    try {
      const res = await apiClient.get(`/attendance?date=${selectedDate}`);
      setAttendance(asArray(res));
    } catch (error) {
      setAttendance([]);
      toast.error("Failed to fetch attendance");
    }
  };

  /* =========================
     SUBMIT
  ========================= */
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      await apiClient.post("/attendance", formData);

      toast.success("Attendance marked successfully");

      setDialogOpen(false);

      setFormData({
        entity_type: "student",
        entity_id: "",
        date: selectedDate,
        status: "present",
        remarks: "",
      });

      fetchAttendance();
    } catch (error) {
      toast.error(
        error?.response?.data?.detail || "Failed to mark attendance"
      );
    }
  };

  /* =========================
     SAFE DATA
  ========================= */
  const safeStudents = useMemo(() => asArray(students), [students]);
  const safeAttendance = useMemo(() => asArray(attendance), [attendance]);

  /* =========================
     STATS (SAFE)
  ========================= */
  const stats = useMemo(() => {
    const list = safeAttendance;

    return {
      present: list.filter((a) => a?.status === "present").length,
      absent: list.filter((a) => a?.status === "absent").length,
      late: list.filter((a) => a?.status === "late").length,
      excused: list.filter((a) => a?.status === "excused").length,
    };
  }, [safeAttendance]);

  return (
    <div className="space-y-6">

      {/* HEADER */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">
            Attendance
          </h2>
          <p className="text-slate-600 mt-1">
            Track student and staff attendance
          </p>
        </div>

        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogTrigger asChild>
            <Button>
              <Plus className="w-4 h-4 mr-2" />
              Mark Attendance
            </Button>
          </DialogTrigger>

          <DialogContent>
            <DialogHeader>
              <DialogTitle>Mark Attendance</DialogTitle>
            </DialogHeader>

            <form onSubmit={handleSubmit} className="space-y-4">

              <div className="space-y-2">
                <Label>Date</Label>
                <Input
                  type="date"
                  value={formData.date}
                  onChange={(e) =>
                    setFormData({ ...formData, date: e.target.value })
                  }
                />
              </div>

              <div className="space-y-2">
                <Label>Student</Label>

                <Select
                  value={formData.entity_id}
                  onValueChange={(value) =>
                    setFormData({ ...formData, entity_id: value })
                  }
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select student" />
                  </SelectTrigger>

                  <SelectContent>
                    {safeStudents.map((student) => (
                      <SelectItem
                        key={student?.id}
                        value={String(student?.id)}
                      >
                        {student?.full_name || "Unknown"} -{" "}
                        {student?.admission_number || "N/A"}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Status</Label>

                <Select
                  value={formData.status}
                  onValueChange={(value) =>
                    setFormData({ ...formData, status: value })
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>

                  <SelectContent>
                    <SelectItem value="present">Present</SelectItem>
                    <SelectItem value="absent">Absent</SelectItem>
                    <SelectItem value="late">Late</SelectItem>
                    <SelectItem value="excused">Excused</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Remarks</Label>
                <Input
                  value={formData.remarks}
                  onChange={(e) =>
                    setFormData({ ...formData, remarks: e.target.value })
                  }
                />
              </div>

              <Button type="submit" className="w-full">
                Mark Attendance
              </Button>

            </form>
          </DialogContent>
        </Dialog>
      </div>

      {/* DATE */}
      <div className="flex items-center gap-4">
        <Calendar className="w-5 h-5" />
        <Input
          type="date"
          value={selectedDate}
          onChange={(e) => setSelectedDate(e.target.value)}
          className="w-auto"
        />
      </div>

      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">

        <Card>
          <CardContent className="p-4">
            Present: {stats.present}
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            Absent: {stats.absent}
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            Late: {stats.late}
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            Excused: {stats.excused}
          </CardContent>
        </Card>

      </div>

      {/* RECORDS */}
      <Card>
        <CardHeader>
          <CardTitle>Attendance Records</CardTitle>
        </CardHeader>

        <CardContent>
          {safeAttendance.length === 0 ? (
            <div className="text-center py-10 text-slate-500">
              No records found
            </div>
          ) : (
            safeAttendance.map((record, i) => (
              <div
                key={record?.id || i}
                className="flex justify-between p-3 border rounded-lg"
              >
                <div>
                  Student ID: {record?.student_id || "N/A"}
                </div>

                <div>{record?.status}</div>
              </div>
            ))
          )}
        </CardContent>
      </Card>

    </div>
  );
};

export default AttendancePage;
